mapper.update:
update clazz
name = #{name}, room = #{room}, begin_date = #{beginDate}, end_date = #{endDate}, master_id = #{masterId}, subject = #{subject}, update_time = #{updateTime},
where id = #{id}

mapper.select:
select cla.id, cla.name, cla.room, cla.begin_date, cla.end_date, cla.master_id, e.name as masterName, case when curdate() > cla.end_date then '已结课' when curdate() < cla.begin_date then '未开班' else '在读中' end as status, cla.subject, cla.create_time, cla.update_time from clazz cla left join emp e on cla.master_id = e.id
cla.name like concat('%',#{name},'%')
and cla.end_date between #{begin} and #{end}
